// Dados mock para desenvolvimento
const mockMatches = [
  {
    id: 123456,
    league: "Campeonato Brasileiro Série A",
    home: "Flamengo",
    away: "Palmeiras",
    score: "2-1",
    time: "65'",
    stats: {
      possession: { home: 55, away: 45 },
      shotsOnTarget: { home: 6, away: 4 }
    }
  },
  {
    id: 123457,
    league: "Premier League",
    home: "Manchester City",
    away: "Liverpool",
    score: "1-1",
    time: "32'",
    stats: {
      possession: { home: 62, away: 38 },
      shotsOnTarget: { home: 3, away: 2 }
    }
  }
];

// Se tiver dados da API real, usa eles
const apiData = $input.first().json;
const matches = apiData?.results || mockMatches;

return matches.map(match => ({ json: match }));

// Classificar risco
function classifyRisk(probability) {
  if (probability >= 0.71) return { level: 'BAIXO', emoji: '🟢', percentage: Math.round(probability * 100) };
  if (probability >= 0.41) return { level: 'MEDIO', emoji: '🟡', percentage: Math.round(probability * 100) };
  return { level: 'ALTO', emoji: '🔴', percentage: Math.round(probability * 100) };
}

// Analisar cada partida
const items = $input.all();
const results = [];

for (const item of items) {
  const match = item.json;

  // Cálculos de probabilidade (simplificados)
  let homeProb = 0.33;

  // Bônus por posse de bola
  if (match.stats?.possession?.home > match.stats?.possession?.away) {
    homeProb += 0.1;
  }

  // Bônus por chutes no gol
  if (match.stats?.shotsOnTarget?.home > match.stats?.shotsOnTarget?.away) {
    homeProb += 0.15;
  }

  homeProb = Math.min(homeProb, 0.85);
  homeProb = Math.max(homeProb, 0.15);

  const awayProb = 1 - homeProb - 0.25; // 25% empates

  const homeRisk = classifyRisk(homeProb);
  const awayRisk = classifyRisk(awayProb);

  // Gerar recomendações
  const recommendations = [];

  if (homeRisk.level !== 'ALTO') {
    recommendations.push({
      type: `VITÓRIA ${match.home.toUpperCase()}`,
      odd: (1/homeProb).toFixed(2),
      risk: homeRisk.level,
      probability: Math.round(homeProb * 100) + '%'
    });
  }

  if (awayRisk.level !== 'ALTO') {
    recommendations.push({
      type: `VITÓRIA ${match.away.toUpperCase()}`,
      odd: (1/awayProb).toFixed(2),
      risk: awayRisk.level,
      probability: Math.round(awayProb * 100) + '%'
    });
  }

  results.push({
    json: {
      match_id: match.id,
      league: match.league,
      teams: `${match.home} vs ${match.away}`,
      score: match.score,
      time: match.time,
      analysis: {
        home_probability: homeProb.toFixed(2),
        home_risk: homeRisk,
        recommendations: recommendations
      }
    }
  });
}

return results;
